public void insert()
{
    next insert();

    if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        if (this.RecVersion != 1)
        {
            return;
        }
    }

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        str descriptiveKeyCollection = strFmt("GroupName='%1'",this.Name);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();

        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("TrackingDimensionGroups");
        contract.parmoperationType("Insert");

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);
        eventClass.send();
    }
}

public void update()
{
    next update();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
        {
            str descriptiveKeyCollection = strFmt("GroupName='%1'",this.Name);

            ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();

            contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
            contract.parmPrimaryCollectionName("TrackingDimensionGroups");
            contract.parmoperationType("Update");

            ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);
            eventClass.send();
        }
    }
}
